import{_ as s,c as n,o as a,a4 as p}from"./chunks/framework.BmPFG-Ev.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"knowledge/nginx.md","filePath":"knowledge/nginx.md","lastUpdated":1722497996000}'),t={name:"knowledge/nginx.md"},e=p(`<h2 id="nginx-命令" tabindex="-1">nginx 命令 <a class="header-anchor" href="#nginx-命令" aria-label="Permalink to &quot;nginx 命令&quot;">​</a></h2><ol><li>启动 ./nginx</li><li>停止 ./nginx -s stop 直接退出 ./nginx -s quit 跑完接口退出</li><li>重启 ./nginx -s reload</li><li>查看配置文件是否出错 ./nginx -t</li><li>查看版本 ./nginx -v</li><li>指定配置文件 ./nginx -c conf/nginx.conf</li></ol><h2 id="负载均衡" tabindex="-1">负载均衡 <a class="header-anchor" href="#负载均衡" aria-label="Permalink to &quot;负载均衡&quot;">​</a></h2><ol><li>默认是轮询的方式</li><li>权重分配 <code>weight</code> = 3</li><li>灾备技术 backup 目标服务器会作为备用服务器</li></ol><p>用法</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http {</span></span>
<span class="line"><span>    upstream aaa {  #这里的aaa替换ip</span></span>
<span class="line"><span>        server 89.0.142.86:80 weight=3;</span></span>
<span class="line"><span>        server 89.0.142.86:80 weight=2;</span></span>
<span class="line"><span>        server 89.0.142.86:80 weight=1 backup;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    server {</span></span>
<span class="line"><span>        location / {</span></span>
<span class="line"><span>            proxy_pass http://aaa;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="配置https" tabindex="-1">配置https <a class="header-anchor" href="#配置https" aria-label="Permalink to &quot;配置https&quot;">​</a></h2><p>下载openssl 配置环境变量</p><ol><li>先生成私钥在终端中输入 生成一个private.key文件</li></ol><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> genpkey</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -algorithm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> RSA</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> private.key</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pkeyopt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rsa_keygen_bits:2048</span></span></code></pre></div><ol start="2"><li>生成证书请求文件CSR 临时文件 用后可删</li></ol><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> req</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -new</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -key</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> private.key</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server.csr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -subj</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/C=CN/ST=GD/L=SZ/O=IT/CN=www.localhost.com&quot;</span></span></code></pre></div><ol start="3"><li>通过csr生成证书</li></ol><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> x509</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -req</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server.csr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -signkey</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> private.key</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server.crt</span></span></code></pre></div><p>注:每个server都是独立的 配置的跨域图片等都需要在配置一次 在文件最后有注释的https配置 打开注释 替换路径即可</p><h2 id="限速技术" tabindex="-1">限速技术 <a class="header-anchor" href="#限速技术" aria-label="Permalink to &quot;限速技术&quot;">​</a></h2><p>限制一分钟接口多少个 limit为自定义变量 限制内存为10兆 每秒发送5个请求</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>limit_req_zone $binary_remote_addr zone=limit:10m rate=5r/s</span></span></code></pre></div><h2 id="缓存技术" tabindex="-1">缓存技术 <a class="header-anchor" href="#缓存技术" aria-label="Permalink to &quot;缓存技术&quot;">​</a></h2><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>proxy_cache_path C:/nginx_cache levels=1:2 keys_zone=cachename:10m max_size=1g inactive=60m;</span></span></code></pre></div><h2 id="nginx-配置文件讲解" tabindex="-1">nginx 配置文件讲解 <a class="header-anchor" href="#nginx-配置文件讲解" aria-label="Permalink to &quot;nginx 配置文件讲解&quot;">​</a></h2><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>#user  nobody;</span></span>
<span class="line"><span>#启动的进程 根据cpu核心 4核</span></span>
<span class="line"><span>worker_processes 1;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#error_log  logs/error.log;</span></span>
<span class="line"><span>#error_log  logs/error.log  notice;</span></span>
<span class="line"><span>#error_log  logs/error.log  info;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#pid        logs/nginx.pid;</span></span>
<span class="line"><span>events {</span></span>
<span class="line"><span>    # 最大并发连接数 worker_processes * worker_connections 每秒处理的请求数</span></span>
<span class="line"><span>    worker_connections 1024;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>http {</span></span>
<span class="line"><span>    # meme类型 文件类型 </span></span>
<span class="line"><span>    include mime.types;</span></span>
<span class="line"><span>    default_type application/octet-stream;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    #log_format  main  &#39;$remote_addr - $remote_user [$time_local] &quot;$request&quot; &#39;</span></span>
<span class="line"><span>    #                  &#39;$status $body_bytes_sent &quot;$http_referer&quot; &#39;</span></span>
<span class="line"><span>    #                  &#39;&quot;$http_user_agent&quot; &quot;$http_x_forwarded_for&quot;&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    #access_log  logs/access.log  main;</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    sendfile on; # nginx特性 处理静态大文件 分布加载 性能好</span></span>
<span class="line"><span>    #tcp_nopush     on;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    #keepalive_timeout  0;</span></span>
<span class="line"><span>    keepalive_timeout 65;   # 超时时间</span></span>
<span class="line"><span>    #压缩 html css js</span></span>
<span class="line"><span>    gzip  on;</span></span>
<span class="line"><span>    gzip_comp_level 5;#1-9 压缩的级别 取中</span></span>
<span class="line"><span>    gzip_types text/css text/javascript application/javascript text/plain text/html application/x-javascript application/x-httpd-php image/jpeg image/gif image/png;    #压缩类型 要压缩的文件</span></span>
<span class="line"><span>    #负载均衡 默认是轮询 </span></span>
<span class="line"><span>    #weight=3 权重</span></span>
<span class="line"><span>    #灾备技术 backup 备份服务器</span></span>
<span class="line"><span>    upstream aaa {  #这里的aaa替换ip</span></span>
<span class="line"><span>        server 127.0.0.1:9001 </span></span>
<span class="line"><span>        server 127.0.0.1:9002</span></span>
<span class="line"><span>        server 127.0.0.1:9003</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    #限速技术 限制一分钟接口多少个 limit为自定义变量  限制内存为10兆 每秒发送5个请求</span></span>
<span class="line"><span>    limit_req_zone $binary_remote_addr zone=limit:10m rate=5r/s</span></span>
<span class="line"><span>    #缓存技术           #路径绝对路径  #缓存的目录结构      #缓存名字  #缓存的大小  最大1g    #失效时间一小时没用到就删除</span></span>
<span class="line"><span>    proxy_cache_path C:/nginx_cache levels=1:2 keys_zone=cachename:10m max_size=1g inactive=60m;</span></span>
<span class="line"><span>    #http服务器管理</span></span>
<span class="line"><span>    server {</span></span>
<span class="line"><span>        listen 8090;    #端口 可以有多个</span></span>
<span class="line"><span>        server_name localhost; #域名</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        #charset koi8-r;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        #access_log  logs/host.access.log  main;</span></span>
<span class="line"><span>        location / {    # 代理 / 代理的路径 </span></span>
<span class="line"><span>            proxy_pass http://aaa;</span></span>
<span class="line"><span>            root html;  #html的跟目录</span></span>
<span class="line"><span>            index index.html index.htm; #文件</span></span>
<span class="line"><span>            try_files $uri $uri/ /index.html; #如果请求的资源不存在，则尝试回退到index.html 404</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        #处理跨域</span></span>
<span class="line"><span>        location /api {         #限制的5 短时间可以10  nodelay没延迟  超过就503</span></span>
<span class="line"><span>            limit_req zone=limit burst=10 nodelay 或者 delay=10</span></span>
<span class="line"><span>            proxy_pass http://aaa</span></span>
<span class="line"><span>            #请求接口只需要 /api/list 就可以   代理转发的地址为   http://localhost:9090/api/list</span></span>
<span class="line"><span>            #如果需要去掉/api</span></span>
<span class="line"><span>            rewrite ^/api/(.*) /$1 break;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        #匹配图片 做防盗链 我的图片被盗  不能看 可以配置白名单 跟在localhost后就行</span></span>
<span class="line"><span>        location ~*.*\\.(jpg|jpeg|gif|png|bmp|ico)$ {</span></span>
<span class="line"><span>            proxy_cache cachename;</span></span>
<span class="line"><span>            proxy_cache_methods GET;</span></span>
<span class="line"><span>            proxy_cache_key $host$uri$is_args$args;</span></span>
<span class="line"><span>            proxy_cache_valid 200 304 5m;#200位置为状态码 缓存5分钟1d为一天</span></span>
<span class="line"><span>            proxy_cache_min_uses 2; #触发两次缓存</span></span>
<span class="line"><span></span></span>
<span class="line"><span>            root html/static;   定位到html/static</span></span>
<span class="line"><span>            valid_referers none blocked loaclhost;  除了localhost其他都不允许</span></span>
<span class="line"><span>            #none 允许referer为空</span></span>
<span class="line"><span>            # blocked 允许referer没有 </span></span>
<span class="line"><span>            #允许来源是loaclhost </span></span>
<span class="line"><span>            #$invalid_referer 根据上边条件 如果条件成立 $invalid_referer为空</span></span>
<span class="line"><span>            if ($invalid_referer) {</span></span>
<span class="line"><span>                return 403;</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>         }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        #error_page  404              /404.html;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        # redirect server error pages to the static page /50x.html</span></span>
<span class="line"><span>        #   错误码 转到哪里</span></span>
<span class="line"><span>        error_page 500 502 503 504 /50x.html;</span></span>
<span class="line"><span>        location = /50x.html {</span></span>
<span class="line"><span>            root html;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        # proxy the PHP scripts to Apache listening on 127.0.0.1:80</span></span>
<span class="line"><span>        #</span></span>
<span class="line"><span>        #location ~ \\.php$ {</span></span>
<span class="line"><span>        #    proxy_pass   http://127.0.0.1;</span></span>
<span class="line"><span>        #}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        # pass the PHP scripts to FastCGI server listening on 127.0.0.1:9000</span></span>
<span class="line"><span>        #</span></span>
<span class="line"><span>        #location ~ \\.php$ {</span></span>
<span class="line"><span>        #    root           html;</span></span>
<span class="line"><span>        #    fastcgi_pass   127.0.0.1:9000;</span></span>
<span class="line"><span>        #    fastcgi_index  index.php;</span></span>
<span class="line"><span>        #    fastcgi_param  SCRIPT_FILENAME  /scripts$fastcgi_script_name;</span></span>
<span class="line"><span>        #    include        fastcgi_params;</span></span>
<span class="line"><span>        #}</span></span>
<span class="line"><span>        # deny access to .htaccess files, if Apache&#39;s document root</span></span>
<span class="line"><span>        # concurs with nginx&#39;s one</span></span>
<span class="line"><span>        #</span></span>
<span class="line"><span>        #location ~ /\\.ht {</span></span>
<span class="line"><span>        #    deny  all;</span></span>
<span class="line"><span>        #}</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>    # another virtual host using mix of IP-, name-, and port-based configuration</span></span>
<span class="line"><span>    #</span></span>
<span class="line"><span>    #server {</span></span>
<span class="line"><span>    #    listen       8000;</span></span>
<span class="line"><span>    #    listen       somename:8080;</span></span>
<span class="line"><span>    #    server_name  somename  alias  another.alias;</span></span>
<span class="line"><span>    #    location / {</span></span>
<span class="line"><span>    #        root   html;</span></span>
<span class="line"><span>    #        index  index.html index.htm;</span></span>
<span class="line"><span>    #    }</span></span>
<span class="line"><span>    #}</span></span>
<span class="line"><span>    # HTTPS server</span></span>
<span class="line"><span>    #       每个server都是独立的 配置的跨域图片等都需要在配置一次 https跟http都可以访问</span></span>
<span class="line"><span>     #配置https 下载openssl 配置环境变量</span></span>
<span class="line"><span>      #1. 先 生成私钥 在终端中输入 生成一个private.key文件</span></span>
<span class="line"><span>     #    openssl genpkey -algorithm RSA -out private.key -pkeyopt rsa_keygen_bits:2048</span></span>
<span class="line"><span>      #  2. 生成证书请求文件CSR</span></span>
<span class="line"><span>      #   openssl req -new -key private.key -out server.csr -subj &quot;/C=CN/ST=GD/L=SZ/O=IT/CN=www.localhost.com&quot;</span></span>
<span class="line"><span>    #    3. 通过csr生成证书</span></span>
<span class="line"><span>      #   openssl x509 -req -in server.csr -signkey private.key -out server.crt</span></span>
<span class="line"><span>        #密钥没用csr文件没用</span></span>
<span class="line"><span>    server {</span></span>
<span class="line"><span>        listen       443 ssl;</span></span>
<span class="line"><span>        server_name  localhost;</span></span>
<span class="line"><span>        ssl_certificate      cert.pem;  #更换路径</span></span>
<span class="line"><span>        ssl_certificate_key  cert.key;  #更换路径   就可以了</span></span>
<span class="line"><span>        ssl_session_cache    shared:SSL:1m;</span></span>
<span class="line"><span>        ssl_session_timeout  5m;</span></span>
<span class="line"><span>        ssl_ciphers  HIGH:!aNULL:!MD5;</span></span>
<span class="line"><span>        ssl_prefer_server_ciphers  on;</span></span>
<span class="line"><span>        location / {</span></span>
<span class="line"><span>            root   html;</span></span>
<span class="line"><span>            index  index.html index.htm;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }  </span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="内置变量" tabindex="-1">内置变量 <a class="header-anchor" href="#内置变量" aria-label="Permalink to &quot;内置变量&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>说明</th></tr></thead><tbody><tr><td>$arg_<em>name</em></td><td>表示请求行中的任意参数，<em>name</em> 为参数名称</td></tr><tr><td>$args</td><td>表示请求行中的参数部分</td></tr><tr><td>$binary_remote_addr</td><td>二进制形式表示的客户端地址</td></tr><tr><td>$body_bytes_sent</td><td>发送到客户端的字节数，不包括响应头</td></tr><tr><td>$bytes_received</td><td>接受到客户端的字节数</td></tr><tr><td>$bytes_sent</td><td>发送到客户端的字节数</td></tr><tr><td>$connection</td><td>连接序列号</td></tr><tr><td>$connection_requests</td><td>当前连接的请求数量</td></tr><tr><td>$connection_time</td><td>连接时间，单位为：ms</td></tr><tr><td>$cookie_<em>name</em></td><td>表示任意 cookie，<em>name</em> 为 cookie 名称</td></tr><tr><td>$date_gmt</td><td>GMT 时间</td></tr><tr><td>$date_local</td><td>本地时间</td></tr><tr><td>$host</td><td>按照以下顺序获取主机信息：请求行中的主机名，或“Host”请求头字段中的主机名，或与请求匹配的服务器名。</td></tr><tr><td>$hostname</td><td>主机名</td></tr><tr><td>$http_<em>name</em></td><td>表示任意请求头；<em>name</em> 为请求头名称，其中破折号被下划线替换并转换为小写；如：$http_user_agent，$http_x_forwarded_for</td></tr><tr><td>$proxy_add_x_forwarded_for</td><td>将 $remote_addr 的值附加到“X−Forwarded−For”客户端请求头中，由逗号分隔。如果客户端请求头中不存在“X−Forwarded−For”，则 $proxy_add_x_forwarded_for 等于 $remote_addr 。</td></tr><tr><td>$proxy_host</td><td>代理服务器的地址和端口</td></tr><tr><td>$proxy_port</td><td>代理服务器的端口</td></tr><tr><td>$query_string</td><td>同 $args</td></tr><tr><td>$remote_addr</td><td>客户端地址</td></tr><tr><td>$remote_port</td><td>客户端端口</td></tr><tr><td>$remote_user</td><td>Basic 身份验证中提供的用户名</td></tr><tr><td>$request</td><td>完整请求行</td></tr><tr><td>$request_body</td><td>请求体</td></tr><tr><td>$request_body_file</td><td>保存请求体的临时文件</td></tr><tr><td>$request_length</td><td>请求长度（包括请求行、头部和请求体）</td></tr><tr><td>$request_method</td><td>请求方法</td></tr><tr><td>$request_time</td><td>请求处理时间，单位为：ms</td></tr><tr><td>$request_uri</td><td>完整请求行</td></tr><tr><td>$scheme</td><td>请求协议，http 或 https</td></tr><tr><td>$server_addr</td><td>接受请求的服务器地址</td></tr><tr><td>$server_name</td><td>接受请求的服务器名称</td></tr><tr><td>$server_port</td><td>接受请求的服务器端口</td></tr><tr><td>$server_protocol</td><td>请求协议，通常为 HTTP/1.0、HTTP/1.1 或 HTTP/2.0</td></tr><tr><td>$ssl_cipher</td><td>建立 SSL 连接所使用的加密套件名称</td></tr><tr><td>$ssl_ciphers</td><td>客户端支持的加密套件列表</td></tr><tr><td>$ssl_client_escaped_cert</td><td>客户端 PEM 格式的证书</td></tr><tr><td>$ssl_protocol</td><td>建立 SSL 连接的协议</td></tr><tr><td>$status</td><td>响应状态码</td></tr><tr><td>$time_iso8601</td><td>ISO 8601 标准格式的本地时间</td></tr><tr><td>$time_local</td><td>Common Log 格式的本地时间</td></tr><tr><td>$upstream_addr</td><td>upstream 服务器的 ip 和端口</td></tr><tr><td>$upstream_bytes_received</td><td>从 upstream 服务器接收的字节数</td></tr><tr><td>$upstream_bytes_sent</td><td>发送给 upstream 服务器的字节数</td></tr><tr><td>$upstream_http_<em>name</em></td><td>表示 upstream 服务器任意响应头，<em>name</em> 为响应头名称，其中破折号被下划线替换并转换为小写</td></tr><tr><td>$upstream_response_length</td><td>upstream 服务器的响应长度，单位为：字节</td></tr><tr><td>$upstream_response_time</td><td>upstream 服务器的响应时间，单位为：秒</td></tr><tr><td>$upstream_status</td><td>upstream 服务器的响应状态码</td></tr><tr><td>$uri</td><td>请求 uri</td></tr></tbody></table>`,24),l=[e];function i(r,c,d,o,h,_){return a(),n("div",null,l)}const k=s(t,[["render",i]]);export{g as __pageData,k as default};
